{
  "query": "query PerfMetrics($input: GetMetricsInput) { analytics { performanceMetrics(input: $input) { id userId metricName metricValue timestamp metadata createdAt } } } }",
  "variables": {
    "input": {
      "limit": 100
    }
  }
}

{
  "query": "query Agg($input: AggregateMetricsInput!) { analytics { aggregateMetrics(input: $input) { avg min max p50 p75 p95 count } } } }",
  "variables": {
    "input": {
      "metricName": "LCP",
      "startDate": "2024-01-01T00:00:00Z",
      "endDate": "2024-01-31T23:59:59Z"
    }
  }
}

{
  "query": "mutation Submit($input: SubmitPerformanceMetricInput!) { analytics { submitPerformanceMetric(input: $input) { success message } } } }",
  "variables": {
    "input": {
      "name": "LCP",
      "value": 2.5,
      "timestamp": 1705315800000
    }
  }
}
